package com.taskmind.backend.task.application;
import static org.junit.jupiter.api.Assertions.*; import com.taskmind.backend.project.domain.model.Project; import com.taskmind.backend.project.domain.repository.ProjectRepository; import java.time.Instant; import java.util.*; import java.util.concurrent.*; import org.junit.jupiter.api.Test; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.boot.test.context.SpringBootTest; import org.springframework.test.annotation.DirtiesContext; import org.springframework.test.context.ActiveProfiles;
@SpringBootTest @ActiveProfiles("test") @DirtiesContext(classMode=DirtiesContext.ClassMode.AFTER_CLASS) class TaskKeyAssignerIntegrationTest{@Autowired TaskKeyAssigner assigner;@Autowired ProjectRepository projects;@Test void assignsUniqueMonotonicKeysConcurrently()throws Exception{var now=Instant.now();var p=projects.save(new Project(UUID.randomUUID(),null,"Keys","KEYS",null,UUID.randomUUID(),null,now,now));var pool=Executors.newFixedThreadPool(6);try{var futures=new ArrayList<Future<String>>();for(int i=0;i<12;i++)futures.add(pool.submit(()->assigner.assign(p.id())));var keys=new HashSet<String>();for(var f:futures)keys.add(f.get(10,TimeUnit.SECONDS));assertEquals(12,keys.size());assertTrue(keys.contains("KEYS-1"));assertTrue(keys.contains("KEYS-12"));}finally{pool.shutdownNow();}}}
